// // This module is designed to select one of four 4-bit input signals (d, c, b, or a) based on a 2-bit selection input (sel). Depending on the value of sel, the output (out) will reflect the selected input: when sel=0, output d; when sel=1, output c; when sel=2, output b; and when sel=3, output a. If sel has an invalid value, the output will be set to an undefined state.
module top_module(
output reg [0:3] out, 
input [0:3] a, b, c, d, 
input [0:1] sel
);always @(sel, a, b, c, d)
case(sel)
	0:	out=a;
	1:	out=b;
	2:	out=c;
	3:	out=d;
default: out=4'bx;
endcase
endmodule
